import{_ as a,o as t,c as p,ai as _}from"./chunks/framework.B1-4-q7d.js";const f=JSON.parse('{"title":"农业农村部办公厅关于印发《2026年农业农村部展会活动计划》的通知2026-03-31","description":"","frontmatter":{"sidebar":false,"aside":false,"editLink":false,"lastUpdated":false,"prev":false,"next":false,"title":"农业农村部办公厅关于印发《2026年农业农村部展会活动计划》的通知2026-03-31","date":"2026-03-31T00:00:00.000Z","source":"农业农村部市场与信息化司","category":"policies","link":"https://www.moa.gov.cn/govpublic/SCYJJXXS/202604/t20260402_6482903.htm","summary":"高级检索\\n索 引  号\\n07B050403202600052\\n信息所属单位\\n市场与信息化司\\n信息名称\\n农业农村部办公厅关于印发《2026年农业农村部展会活动计划》的通知\\n文　　号\\n农办市[2026]5号\\n生效日期\\n2026年03月31日\\n发布日期\\n2026年03月31日\\n内容概述\\n经农业农村部常务会议审议，现将《2026年农业农村部展会活动计划》予以印发，并就有关事宜通知如下。\\n索 引  号\\n...\\n","contentHash":"51848e161ac2eef100b702e6cfc54459","tags":["智慧农业","政策法规"]},"headers":[],"relativePath":"policies/2026-03-31-农业农村部办公厅关于印发-2026年农业农村部展会活动计划-的通知.md","filePath":"policies/2026-03-31-农业农村部办公厅关于印发-2026年农业农村部展会活动计划-的通知.md"}'),n={name:"policies/2026-03-31-农业农村部办公厅关于印发-2026年农业农村部展会活动计划-的通知.md"};function o(r,e,l,s,i,c){return t(),p("div",null,[...e[0]||(e[0]=[_('<h1 id="农业农村部办公厅关于印发《2026年农业农村部展会活动计划》的通知2026-03-31" tabindex="-1">农业农村部办公厅关于印发《2026年农业农村部展会活动计划》的通知2026-03-31 <a class="header-anchor" href="#农业农村部办公厅关于印发《2026年农业农村部展会活动计划》的通知2026-03-31" aria-label="Permalink to &quot;农业农村部办公厅关于印发《2026年农业农村部展会活动计划》的通知2026-03-31&quot;">​</a></h1><blockquote><p>来源: <a href="https://www.moa.gov.cn/govpublic/SCYJJXXS/202604/t20260402_6482903.htm" target="_blank" rel="noreferrer">农业农村部市场与信息化司</a><br> 日期: 2026-03-31 摘要: 高级检索 索 引 号 07B050403202600052 信息所属单位 市场与信息化司 信息名称 农业农村部办公厅关于印发《2026年农业农村部展会活动计划》的通知 文　　号 农办市[2026]5号 生效日期 2026年03月31日 发布日期 2026年03月31日 内容概述 经农业农村部常务会议审议，现将《2026年农业农村部展会活动计划》予以印发，并就有关事宜通知如下。 索 引 号 ...</p></blockquote><p>高级检索</p><h2 id="农业农村部办公厅关于印发《2026年农业农村部展会活动计划》的通知" tabindex="-1">农业农村部办公厅关于印发《2026年农业农村部展会活动计划》的通知 <a class="header-anchor" href="#农业农村部办公厅关于印发《2026年农业农村部展会活动计划》的通知" aria-label="Permalink to &quot;农业农村部办公厅关于印发《2026年农业农村部展会活动计划》的通知&quot;">​</a></h2><p>发布时间：2026年03月31日</p><p>字体：[大 中 小]</p><p>经农业农村部常务会议审议，现将《2026年农业农村部展会活动计划》予以印发，并就有关事宜通知如下。</p><p>一、聚焦服务中心工作。2026年是“十五五”开局之年，做好“三农”工作至关重要。举办展会活动要深入贯彻党中央、国务院决策部署，围绕农业农村年度重点工作，精心组织谋划，健全工作机制，充分发动各方力量，为扎实推进乡村全面振兴提供有力支持。</p><p>二、注重实效提升质量。坚持市场化、专业化、国际化、品牌化、信息化办展方向，推动展会活动提质增效，培育打造一批产业特色鲜明、服务功能完善、社会影响广泛的品牌展会活动。充分发挥展示成果、促进贸易、推动交流的作用，加大参展商、采购商邀请力度，以更丰富的形式展示农业农村成就，以更专业的服务促进主体间、地域间、行业间合作，发挥实实在在的平台载体作用。</p><p>三、突出促进消费主题。围绕促进消费、做强品牌，设置促消费专区，开展品牌宣推、消费促进等活动。优化展区规划布局，创新消费场景，打造农文旅融合沉浸式体验，让展会活动成为优质农产品的展销馆、农耕文化的体验馆、业态跨界的融合馆。聚焦为农助农，开展公益性品牌推介和产销对接活动，促进欠发达地区“土特产”走进主销区。</p><p>四、严格规范举办展会活动。严格落实党中央、国务院关于展会活动的有关要求，务实规范节约办展。切实落实《农业农村部展会活动管理办法》的规定，坚持“谁主办谁负责、谁组织谁负责”的原则，展会活动主办单位要加强统筹管理，履行好报批或变更程序，谋划好主题、内容和活动等事宜。未经批准不得在展会活动中嵌套举办节庆、论坛等活动，规范组织招展招商、品牌发布、信息交流等活动，坚决禁止借展会活动之名行不相关之事。严格遵守财经纪律，落实展会活动预算、采购、收支等管理规定，严防违纪违规行为发生。</p><p>五、及时报送工作总结。认真做好展会活动报备和总结工作，提炼创新组织、市场运作、专业办展等方面的经验做法，展会活动结束1个月内将总结报告（包括纸质版和电子版）报送至农业农村部市场与信息化司。</p><p>联 系 人：农业农村部市场与信息化司　吴自立</p><p>联系电话：010-59191724，59192101（传真）</p><p>电子邮箱：scsscjsc@agri.gov.cn</p><p>附件：2026年农业农村部展会活动计划</p><p>农业农村部办公厅</p><p>2026年3月31日</p><p>附件：</p><ul><li>附件：2026年农业农村部展会活动计划.doc</li><li>农办市[2026]5号.ofd</li></ul><p>相关新闻：</p><p>扫一扫在手机打开当前页</p><p><a href="https://www.moa.gov.cn/govpublic/SCYJJXXS/202604/t20260402_6482903.htm" target="_blank" rel="noreferrer">阅读原文</a></p>',23)])])}const h=a(n,[["render",o]]);export{f as __pageData,h as default};
